import{_ as s,o as i,c as t,a2 as a}from"./chunks/framework.D2pTuMig.js";const m=JSON.parse('{"title":"Compte & Audiences","description":"","frontmatter":{"title":"Compte & Audiences"},"headers":[],"relativePath":"docs/fr/faq/account-audiences.md","filePath":"docs/fr/faq/account-audiences.md"}'),r={name:"docs/fr/faq/account-audiences.md"};function n(o,e,u,l,c,d){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="compte-equipe-audiences" tabindex="-1">Compte, Équipe &amp; Audiences <a class="header-anchor" href="#compte-equipe-audiences" aria-label="Permalink to &quot;Compte, Équipe &amp; Audiences&quot;">​</a></h1><h2 id="comment-ajouter-un-nouvel-utilisateur" tabindex="-1">Comment ajouter un nouvel utilisateur ? <a class="header-anchor" href="#comment-ajouter-un-nouvel-utilisateur" aria-label="Permalink to &quot;Comment ajouter un nouvel utilisateur ?&quot;">​</a></h2><p>Rendez-vous dans <strong>Mon Organisation → Équipe</strong> et cliquez sur <code>+ Ajouter un membre</code>. Recommandé : ayez toujours au moins un backup pour assurer la réactivité sous 48h.</p><h2 id="comment-referencer-une-nouvelle-audience" tabindex="-1">Comment référencer une nouvelle audience ? <a class="header-anchor" href="#comment-referencer-une-nouvelle-audience" aria-label="Permalink to &quot;Comment référencer une nouvelle audience ?&quot;">​</a></h2><p>Allez dans <strong>Monétisation → Catalogue</strong> et cliquez sur <code>+ Nouvelle audience</code>. Remplissez les fiches avec soin (Marque, Persona, Panier Moyen) — c&#39;est ce qui convaincra les annonceurs.</p><p>→ <a href="/handbook/docs/fr/publishers/audience-setup.html">Guide détaillé : Configuration d&#39;Audience</a></p><h2 id="faut-il-creer-plusieurs-comptes-si-j-ai-plusieurs-sites" tabindex="-1">Faut-il créer plusieurs comptes si j&#39;ai plusieurs sites ? <a class="header-anchor" href="#faut-il-creer-plusieurs-comptes-si-j-ai-plusieurs-sites" aria-label="Permalink to &quot;Faut-il créer plusieurs comptes si j&#39;ai plusieurs sites ?&quot;">​</a></h2><p>Non. Vous pouvez gérer autant d&#39;audiences que vous le souhaitez depuis un seul compte getinside. Chaque site peut avoir sa propre fiche audience indépendante.</p><h2 id="getinside-est-il-present-a-l-international" tabindex="-1">getinside est-il présent à l&#39;international ? <a class="header-anchor" href="#getinside-est-il-present-a-l-international" aria-label="Permalink to &quot;getinside est-il présent à l&#39;international ?&quot;">​</a></h2><p>Oui, getinside opère dans toute l&#39;Europe. Vous pouvez ajouter vos audiences européennes et recevoir des campagnes ciblées pour ces pays.</p><h2 id="comment-suivre-mes-filleuls-affiliation" tabindex="-1">Comment suivre mes filleuls (affiliation) ? <a class="header-anchor" href="#comment-suivre-mes-filleuls-affiliation" aria-label="Permalink to &quot;Comment suivre mes filleuls (affiliation) ?&quot;">​</a></h2><p>L&#39;état de vos filleuls est visible dans l&#39;onglet <strong>Affiliation</strong>. Vous touchez une commission récurrente de <strong>20%</strong> sur les frais de plateforme générés par leur activité. Vos gains apparaissent dans <strong>Transactions → Revenus</strong> et peuvent être retirés ou réinvestis depuis votre Wallet.</p><h2 id="pourquoi-mon-score-distributeur-a-baisse" tabindex="-1">Pourquoi mon &quot;Score Distributeur&quot; a baissé ? <a class="header-anchor" href="#pourquoi-mon-score-distributeur-a-baisse" aria-label="Permalink to &quot;Pourquoi mon &quot;Score Distributeur&quot; a baissé ?&quot;">​</a></h2><p>Le score est recalculé dynamiquement. Causes fréquentes : délai de réponse &gt; 48h, refus de campagnes sans contre-proposition, volumes distribués inférieurs aux engagements, CPM trop élevé vs la concurrence.</p><p>→ <a href="/handbook/docs/fr/publishers/score-distributor.html">Guide complet : Score Distributeur</a></p><h2 id="comment-rendre-ma-fiche-audience-attractive-pour-les-annonceurs" tabindex="-1">Comment rendre ma fiche audience attractive pour les annonceurs ? <a class="header-anchor" href="#comment-rendre-ma-fiche-audience-attractive-pour-les-annonceurs" aria-label="Permalink to &quot;Comment rendre ma fiche audience attractive pour les annonceurs ?&quot;">​</a></h2><p>Les annonceurs parcourent le catalogue comme une place de marché — votre fiche est votre vitrine. Pour maximiser vos chances de recevoir des offres :</p><ul><li><strong>Soignez les visuels :</strong> photos de vos emballages, exemples de colis, captures de vos emails.</li><li><strong>Décrivez précisément votre persona :</strong> âge, catégorie de produit, fréquence d&#39;achat, géolocalisation.</li><li><strong>Renseignez un Panier Moyen (AOV) réaliste :</strong> un chiffre précis rassure plus qu&#39;une fourchette vague.</li><li><strong>Activez plusieurs formats :</strong> un distributeur proposant Insertion Colis + Emailing est plus attractif qu&#39;un monoforme.</li></ul><p>→ <a href="/handbook/docs/fr/publishers/audience-setup.html">Guide complet : Configuration d&#39;Audience</a></p><h2 id="peut-on-gerer-plusieurs-sites-depuis-un-seul-compte-getinside" tabindex="-1">Peut-on gérer plusieurs sites depuis un seul compte getinside ? <a class="header-anchor" href="#peut-on-gerer-plusieurs-sites-depuis-un-seul-compte-getinside" aria-label="Permalink to &quot;Peut-on gérer plusieurs sites depuis un seul compte getinside ?&quot;">​</a></h2><p>Oui. Un seul compte peut héberger autant de fiches audiences que vous avez de sites ou de flux logistiques distincts. Chaque audience est indépendante et peut avoir ses propres tarifs, formats disponibles et périodes d&#39;ouverture.</p>',21)])])}const h=s(r,[["render",n]]);export{m as __pageData,h as default};
